  async createTone(
    frequency: number,
    duration: number,
    volume: number = 0.5,
  ): Promise<void> {
    if (!this.audioContext || !this.outputNode) {
      throw new Error('Audio context not initialized');
    }

    const oscillator = this.audioContext.createOscillator();
    const gainNode = this.audioContext.createGain();

    oscillator.frequency.value = frequency;
    oscillator.type = 'sine';

    gainNode.gain.value = 0;
    gainNode.gain.setValueAtTime(0, this.audioContext.currentTime);
    gainNode.gain.linearRampToValueAtTime(
      volume,
      this.audioContext.currentTime + 0.01,
    );
    gainNode.gain.linearRampToValueAtTime(
      0,
      this.audioContext.currentTime + duration - 0.01,
    );

    oscillator.connect(gainNode);
    gainNode.connect(this.outputNode);

    const startTime = this.audioContext.currentTime;

    // Clean up nodes after tone finishes with proper error handling
    const cleanup = () => {
      try {
        oscillator.disconnect();
        gainNode.disconnect();
      } catch (error) {
        // Ignore errors during cleanup - nodes may already be disconnected
      }
    };

    oscillator.addEventListener('ended', cleanup);

    // Ensure cleanup happens even if oscillator fails to start
    oscillator.addEventListener('error', cleanup);

    // Set up timeout cleanup as fallback
    const timeoutId = setTimeout(() => {
      cleanup();
      oscillator.removeEventListener('ended', cleanup);
      oscillator.removeEventListener('error', cleanup);
    }, (duration + 1) * 1000); // 1 second buffer

    // Override cleanup to also clear timeout
    const originalCleanup = cleanup;
    const enhancedCleanup = () => {
      clearTimeout(timeoutId);
      originalCleanup();
      oscillator.removeEventListener('ended', enhancedCleanup);
      oscillator.removeEventListener('error', enhancedCleanup);
    };

    oscillator.removeEventListener('ended', cleanup);
    oscillator.removeEventListener('error', cleanup);
    oscillator.addEventListener('ended', enhancedCleanup);
    oscillator.addEventListener('error', enhancedCleanup);

    oscillator.start(startTime);
    oscillator.stop(startTime + duration);

    this.emitEvent('toneplayed', {
      frequency,
      duration,
      startTime: this.clock.now(),
    });
  }

  private monitorAudioLevel(): void {
    if (!this.analyser || !this.isRecording) {
      if (this.monitoringFrameId) {
        cancelAnimationFrame(this.monitoringFrameId);
        this.monitoringFrameId = undefined;
      }
      return;
    }

    try {
      const dataArray = new Uint8Array(this.analyser.frequencyBinCount);
      this.analyser.getByteFrequencyData(dataArray);

      const average = dataArray.reduce((a, b) => a + b) / dataArray.length;
      const level = average / 255;

      this.emitEvent('audiolevel', { level });

      if (this.isRecording) {
        this.monitoringFrameId = requestAnimationFrame(() => this.monitorAudioLevel());
      } else {
        if (this.monitoringFrameId) {
          cancelAnimationFrame(this.monitoringFrameId);
          this.monitoringFrameId = undefined;
        }
      }
    } catch (error) {
      // If monitoring fails, stop monitoring to prevent memory leaks
      console.warn('Audio level monitoring failed:', error);
      if (this.monitoringFrameId) {
        cancelAnimationFrame(this.monitoringFrameId);
        this.monitoringFrameId = undefined;
      }
    }
  }

  private handleDeviceChange(): void {
    this.emitEvent('devicechange', { changed: true });
  }

  get currentTime(): number {
    return this.audioContext?.currentTime || 0;
  }

  get sampleRate(): number {
    return this.audioContext?.sampleRate || 0;
  }
}

